type regenerateEnrollmentTokenResponse struct {
	Token     string    `json:"token"`
	ExpiresAt time.Time `json:"expires_at"`
}

type rotateCertResponse struct {
	NewKey         bool   `json:"new_key"`
	CertificatePEM string `json:"certificate_pem,omitempty"`
	CACertPEM      string `json:"ca_certificate_pem,omitempty"`
}

// handleRotateCert implements POST /api/v1/hosts/{id}/rotate-cert?new_key=...
// (ADR 0004 §7.1 force-rotate).
//
//   - new_key=false (default): the server re-signs the existing public key
//     immediately and returns the new cert. The agent picks it up on the
//     next poll via SaveCertificateAndUpdateHostCert's overlap window.
//   - new_key=true: a pending_rekey flag is set on the host row. The next
//     poll response carries rekey_required + a single-use enrollment token
//     the agent uses to re-enroll its freshly generated keypair.
func (s *Server) handleRotateCert(w http.ResponseWriter, r *http.Request) {
	id := chi.URLParam(r, "id")
	newKey := strings.EqualFold(r.URL.Query().Get("new_key"), "true")

	host, err := s.store.GetHost(r.Context(), id)
	if errors.Is(err, store.ErrNotFound) {
		writeError(w, http.StatusNotFound, "host not found")
		return
	}
	if err != nil {
		s.logger.Error("get host for rotate-cert", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to get host")
		return
	}

	if newKey {
		if err := s.store.SetPendingRekey(r.Context(), host.ID); err != nil {
			if errors.Is(err, store.ErrRekeyAlreadyPending) {
				writeError(w, http.StatusConflict, "rekey already pending")
				return
			}
			s.logger.Error("set pending rekey", "error", err)
			writeError(w, http.StatusInternalServerError, "failed to schedule rekey")
			return
		}
		s.recordAuditAction(r.Context(), auditHostRotateCertRequested, host.ID, "new_key=true")
		writeJSON(w, http.StatusAccepted, rotateCertResponse{NewKey: true})
		return
	}

	certInfo, err := s.store.GetCertificateInfo(r.Context(), host.ID)
	if err != nil {
		s.logger.Error("get cert info for rotate-cert", "error", err)
		writeError(w, http.StatusInternalServerError, "no current cert to re-sign")
		return
	}
	signed, err := s.signHostCert(r.Context(), host, certInfo)
	if err != nil {
		s.logger.Error("sign cert for rotate-cert", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to sign new cert")
		return
	}
	if err := s.store.SaveCertificateAndUpdateHostCert(r.Context(), host.ID, signed.certPEM, signed.fp, signed.notBefore, signed.notAfter); err != nil {
		s.logger.Error("save rotated cert", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to persist new cert")
		return
	}
	s.metrics.recordSignature(host.CAID)
	s.recordAuditAction(r.Context(), auditHostRotateCertRequested, host.ID, "new_key=false")

	writeJSON(w, http.StatusOK, rotateCertResponse{
		NewKey:         false,
		CertificatePEM: string(signed.certPEM),
		CACertPEM:      string(signed.caCertPEM),
	})
}

// handleReenroll is the explicit re-enrollment endpoint (ADR 0004 §7.1).
// It delegates to mintEnrollmentTokenForHost — identical mechanics to
// handleRegenerateEnrollmentToken — but exists as a separate route so
// operator UIs can present "re-enroll" as a discrete action (e.g. when a
// host has lost its key material), distinct from the "regenerate token"
// fix-up that handleRegenerateEnrollmentToken serves.
func (s *Server) handleReenroll(w http.ResponseWriter, r *http.Request) {
	s.mintEnrollmentTokenForHost(w, r, "reenroll")
}

// handleRegenerateEnrollmentToken mints a fresh single-use enrollment token
// bound to an existing host row (ADR 0004 §7.1 — "regenerates the token
// without churning the row"). Previous active tokens for the same host are
// invalidated atomically. The host row, its IP allocation, group membership,
// and audit history are preserved.
func (s *Server) handleRegenerateEnrollmentToken(w http.ResponseWriter, r *http.Request) {
	s.mintEnrollmentTokenForHost(w, r, "regenerate-token")
}

// mintEnrollmentTokenForHost is the shared implementation of the
// regenerate-token and reenroll endpoints. The reason argument flows into
// the audit details column so the timeline distinguishes the two.
func (s *Server) mintEnrollmentTokenForHost(w http.ResponseWriter, r *http.Request, reason string) {
	id := chi.URLParam(r, "id")
	host, err := s.store.GetHost(r.Context(), id)
	if errors.Is(err, store.ErrNotFound) {
		writeError(w, http.StatusNotFound, "host not found")
		return
	}
	if err != nil {
		s.logger.Error("get host", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to get host")
		return
	}

	tokenStr := uuid.New().String()
	expiresAt := time.Now().Add(s.tokenTTLFor(r.Context(), host.NetworkID))
	if err := s.store.CreateTokenForHost(r.Context(), host.ID, tokenStr, expiresAt); err != nil {
		s.logger.Error("create enrollment token", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to mint token")
		return
	}
	details := host.Name
	if reason != "" {
		details = reason + ": " + host.Name
	}
	s.recordAuditAction(r.Context(), auditHostReenrollRequested, host.ID, details)

	writeJSON(w, http.StatusCreated, regenerateEnrollmentTokenResponse{
		Token:     tokenStr,
		ExpiresAt: expiresAt,
	})
}

func (s *Server) handleUpdateHost(w http.ResponseWriter, r *http.Request) {
	id := chi.URLParam(r, "id")

	// Load host by ID
	host, err := s.store.GetHost(r.Context(), id)
	if errors.Is(err, store.ErrNotFound) {
		writeError(w, http.StatusNotFound, "host not found")
		return
	}
	if err != nil {
		s.logger.Error("get host", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to get host")
		return
	}

	// API trusts the bearer token for authorisation; per-CA ownership is enforced only in the Web layer (handleHostUpdate). Matches handleCreateHost/handleDeleteHost behaviour.

	// Decode request body (lenient for PATCH, forward-compatible)
	var req updateHostRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeError(w, http.StatusBadRequest, "invalid request body")
		return
	}

	// Snapshot before state for diff and triggers
	before := *host
	if before.Advanced != nil {
		beforeAdv := *before.Advanced
		before.Advanced = &beforeAdv
	}

	// Validate and merge fields
	if req.Name != nil {
		name := strings.TrimSpace(*req.Name)
		if name == "" {
			writeError(w, http.StatusBadRequest, "name must not be empty")
			return
		}
		host.Name = name
	}

	if req.NebulaIPs != nil {
		if err := validateHostIPs(r.Context(), s.store, host.NetworkID, *req.NebulaIPs, host.ID); err != nil {
			if IsHostIPValidationError(err) {
				writeError(w, http.StatusBadRequest, err.Error())
				return
			}
			s.logger.Error("validate host ips", "error", err)
			writeError(w, http.StatusInternalServerError, "failed to validate nebula_ips")
			return
		}
		host.NebulaIPs = *req.NebulaIPs
	}

	if req.Groups != nil {
		for _, g := range *req.Groups {
			if strings.TrimSpace(g) == "" {
				writeError(w, http.StatusBadRequest, "group names must not be empty")
				return
			}
		}
		host.Groups = *req.Groups
	}

	if req.Role != nil {
		role := models.HostRole(*req.Role)
		if !models.ValidRole(role) {
			writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid role: %q", *req.Role))
			return
		}
		host.Role = role
		host.IsLighthouse = role == models.HostRoleLighthouse
		host.IsRelay = role == models.HostRoleRelay
	}

	if req.PublicIP != nil {
		publicIP := strings.TrimSpace(*req.PublicIP)
		if publicIP != "" {
			if _, err := models.ValidateIPAddr("public_ip", publicIP); err != nil {
				writeError(w, http.StatusBadRequest, err.Error())
				return
			}
		}
		host.PublicIP = publicIP
	}

	if req.ListenPort != nil {
		if *req.ListenPort < 0 || *req.ListenPort > 65535 {
			writeError(w, http.StatusBadRequest, "listen_port must be between 0 and 65535")
			return
		}
		host.ListenPort = *req.ListenPort

package api

import (
	"context"
	"encoding/json"
	"expvar"
	"log/slog"
	"net/http"
	"time"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	poppkg "github.com/juev/nebula-mesh/internal/api/pop"
	"github.com/juev/nebula-mesh/internal/auth"
	"github.com/juev/nebula-mesh/internal/configgen"
	"github.com/juev/nebula-mesh/internal/keystore"
	"github.com/juev/nebula-mesh/internal/pki"
	"github.com/juev/nebula-mesh/internal/ratelimit"
	"github.com/juev/nebula-mesh/internal/store"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

// Server is the HTTP API server.
type Server struct {
	router         chi.Router
	store          store.Store
	caResolver     *pki.CAResolver // resolves CAs by id from the store (multi-CA)
	master         *keystore.Master
	defaultCAID    string // id of the seeded default CA (when imported)
	logger         *slog.Logger
	metrics        *metrics
	metricsEnabled bool
	hostSeen           HostSeenEmitter
	limiter            *ratelimit.Limiter
	passwordPolicy     auth.Policy
	enrollmentTokenTTL time.Duration
	nonceCache         *poppkg.NonceCache
}

// NewServer creates a new API server.
func NewServer(s store.Store, logger *slog.Logger) *Server {
	srv := &Server{
		store:              s,
		logger:             logger,
		metrics:            newMetrics(s),
		metricsEnabled:     true,
		passwordPolicy:     auth.Default(),
		enrollmentTokenTTL: 24 * time.Hour,
		nonceCache:         poppkg.NewNonceCache(poppkg.NonceCacheConfig{}),
	}
	srv.setupRoutes()
	return srv
}

// nonces returns the per-server replay-protection cache.
func (s *Server) nonces() *poppkg.NonceCache { return s.nonceCache }

// WithEnrollmentTokenTTL sets the default enrollment-token TTL applied when
// the per-network override is unset. Default is 24h (ADR 0004 §7.1).
func (s *Server) WithEnrollmentTokenTTL(ttl time.Duration) {
	if ttl > 0 {
		s.enrollmentTokenTTL = ttl
	}
}

// tokenTTLFor resolves the enrollment-token TTL for the network. Order of
// precedence: per-network `enrollment_token_ttl` value in `network_config`,
// then the server-level default, then 24h.
func (s *Server) tokenTTLFor(ctx context.Context, networkID string) time.Duration {
	if networkID != "" {
		v, err := s.store.GetNetworkConfig(ctx, networkID, "enrollment_token_ttl")
		if err == nil && v != "" {
			if d, perr := time.ParseDuration(v); perr == nil && d > 0 {
				return d
			}
		}
	}
	if s.enrollmentTokenTTL > 0 {
		return s.enrollmentTokenTTL
	}
	return 24 * time.Hour
}

// WithCAResolver attaches a CAResolver. Must be called before ServeHTTP.
// When set, host signing operations look up the CA by host.CAID; the
// legacy single-CA fallback is used only when host.CAID is empty.
func (s *Server) WithCAResolver(r *pki.CAResolver) {
	s.caResolver = r
}

// WithMaster sets the master keystore used to create new CAs.
func (s *Server) WithMaster(m *keystore.Master) { s.master = m }

// RecordLogin records an operator login attempt against the server's
// Prometheus metrics. Exposed so the Web UI handlers (a separate package)
// can plumb their login outcomes through without an import cycle.
//
// Result is one of "ok" / "denied" / "error"; factor is one of
// "password" / "totp" / "recovery" / "oidc".
func (s *Server) RecordLogin(result, factor string) {
	s.metrics.recordLogin(result, factor)
}

// WithRateLimiter installs a rate-limit middleware. nil disables limiting.
func (s *Server) WithRateLimiter(l *ratelimit.Limiter) {
	s.limiter = l
	s.setupRoutes()
}

// WithPasswordPolicy installs the policy applied to every server-side
// password-setting path (operator create, future operator reset).
func (s *Server) WithPasswordPolicy(p auth.Policy) { s.passwordPolicy = p }

// WithMetricsEnabled toggles the Prometheus /metrics endpoint. Disable in
// air-gapped deployments where the exporter is not scraped. Must be called
// before the router is exercised by ServeHTTP — re-wires the routes.
func (s *Server) WithMetricsEnabled(enabled bool) {
	s.metricsEnabled = enabled
	s.setupRoutes()
}

// HostSeenEmitter is invoked after every successful agent poll so the Web
// UI can stream a live "host X just polled" event over its SSE endpoint.
// hostID is the DB id, lastSeen is the wall-clock timestamp the agent's
// poll was observed at, and networkID is included so per-network views can
// filter without an extra lookup.
type HostSeenEmitter func(hostID string, lastSeen time.Time, networkID string)

// WithHostSeenEmitter wires the callback the API server fires when an
// agent polls. Passing nil disables emission.
func (s *Server) WithHostSeenEmitter(emit HostSeenEmitter) {
	s.hostSeen = emit
}

// WithDefaultCAID records the id of the CA seeded from the legacy
// on-disk material. Used when host.CAID matches this id to short-circuit
// to the legacy in-memory CAManager.
func (s *Server) WithDefaultCAID(id string) {
	s.defaultCAID = id
}

func (s *Server) setupRoutes() {
	r := chi.NewRouter()
	r.Use(middleware.RequestID)
	r.Use(middleware.Recoverer)
	r.Use(requestLogger(s.logger))
	r.Use(s.metricsMiddleware())
	r.Use(maxBodySize(1 << 20)) // 1MB

	// Public endpoints — operations and enrollment
	r.Get("/health", s.handleHealth) // legacy alias
	r.Get("/healthz", s.handleHealth)
	r.Get("/readyz", s.handleReady)
	if s.metricsEnabled {
		r.Method("GET", "/metrics", promhttp.HandlerFor(s.metrics.reg, promhttp.HandlerOpts{}))
	}
	r.Method("GET", "/debug/vars", expvar.Handler())
	r.Group(func(r chi.Router) {
		r.Use(s.rateLimitMiddleware("enroll"))
		r.Post("/api/v1/enroll", s.handleEnroll)
	})
	r.Group(func(r chi.Router) {
		r.Use(s.rateLimitMiddleware("agent_poll"))
		r.Get("/api/v1/agent/updates", s.handleAgentUpdates)
	})

	// Protected endpoints (require API key)
	r.Group(func(r chi.Router) {
		r.Use(s.rateLimitMiddleware("api"))
		r.Use(bearerAuth(s.store))
		r.Post("/api/v1/networks", s.handleCreateNetwork)
		r.Get("/api/v1/networks", s.handleListNetworks)
		r.Get("/api/v1/networks/{id}", s.handleGetNetwork)
		r.Post("/api/v1/hosts", s.handleCreateHost)
		r.Get("/api/v1/hosts", s.handleListHosts)
		r.Get("/api/v1/hosts/{id}", s.handleGetHost)
		r.Patch("/api/v1/hosts/{id}", s.handleUpdateHost)
		r.Delete("/api/v1/hosts/{id}", s.handleDeleteHost)
		r.Post("/api/v1/hosts/{id}/block", s.handleBlockHost)
		r.Post("/api/v1/hosts/{id}/unblock", s.handleUnblockHost)
		r.Post("/api/v1/hosts/{id}/enrollment-token", s.handleRegenerateEnrollmentToken)
		r.Post("/api/v1/hosts/{id}/rotate-cert", s.handleRotateCert)
		r.Post("/api/v1/hosts/{id}/reenroll", s.handleReenroll)
		r.Post("/api/v1/hosts/{id}/mobile-bundle", s.handleMobileBundle)
		r.Get("/api/v1/blocklist", s.handleGetBlocklist)
		r.Get("/api/v1/networks/{id}/firewall", s.handleGetFirewall)
		r.Put("/api/v1/networks/{id}/firewall", s.handleUpdateFirewall)
		r.Get("/api/v1/audit-log", s.handleGetAuditLog)
		r.Get("/api/v1/operators", s.handleListOperators)
		r.Post("/api/v1/operators", s.handleCreateOperator)
		r.Post("/api/v1/operators/{id}/disable", s.handleDisableOperator)
		r.Post("/api/v1/operators/{id}/enable", s.handleEnableOperator)
		r.Get("/api/v1/operators/{id}/api-keys", s.handleListOperatorAPIKeys)
		r.Post("/api/v1/operators/{id}/api-keys", s.handleCreateOperatorAPIKey)
		r.Delete("/api/v1/operators/{id}/api-keys/{kid}", s.handleRevokeOperatorAPIKey)
		r.Get("/api/v1/cas", s.handleListCAs)
		r.Post("/api/v1/cas", s.handleCreateCA)
		r.Get("/api/v1/cas/{id}", s.handleGetCAByID)
		r.Delete("/api/v1/cas/{id}", s.handleDeleteCA)
		r.Post("/api/v1/cas/{id}/rotate", s.handleRotateCA)
		r.Get("/api/v1/settings", s.handleGetSettings)
		r.Patch("/api/v1/settings", s.handlePatchSettings)
	})

	s.router = r
}

// ServeHTTP implements http.Handler.
func (s *Server) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	s.router.ServeHTTP(w, r)
}

func (s *Server) handleHealth(w http.ResponseWriter, _ *http.Request) {
	writeJSON(w, http.StatusOK, map[string]string{"status": "ok"})
}

// handleReady reports readiness — verifies the database is reachable.
func (s *Server) handleReady(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := contextWithTimeout(r.Context(), 2*time.Second)
	defer cancel()
	if err := s.store.Ping(ctx); err != nil {
		writeJSON(w, http.StatusServiceUnavailable, map[string]string{"status": "unavailable", "error": err.Error()})
		return
	}
	writeJSON(w, http.StatusOK, map[string]string{"status": "ready"})
}

// writeJSON sends a JSON response.
func writeJSON(w http.ResponseWriter, status int, v any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	if err := json.NewEncoder(w).Encode(v); err != nil {
		slog.Error("encode JSON response", "error", err)
	}
}

// writeError sends a JSON error response.
func writeError(w http.ResponseWriter, status int, msg string) {
	writeJSON(w, status, map[string]string{"error": msg})
}

package api

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"time"

	"github.com/go-chi/chi/v5"
	"github.com/google/uuid"
	"github.com/juev/nebula-mesh/internal/keystore"
	"github.com/juev/nebula-mesh/internal/models"
	"github.com/juev/nebula-mesh/internal/pki"
	"github.com/juev/nebula-mesh/internal/store"
)

type createCARequest struct {
	Name     string `json:"name"`
	Duration string `json:"duration,omitempty"` // e.g. "8760h"
}

type caResponse struct {
	*models.CA
	IsDefault bool `json:"is_default"`
}

func (s *Server) toCAResponse(c *models.CA) caResponse {
	return caResponse{CA: c, IsDefault: c.ID == s.defaultCAID}
}

// handleListCAs returns all CAs visible to the actor. Admin sees all,
// non-admin sees only CAs they own.
func (s *Server) handleListCAs(w http.ResponseWriter, r *http.Request) {
	var (
		cas []*models.CA
		err error
	)
	if actorIsAdmin(r.Context()) {
		cas, err = s.store.ListCAs(r.Context())
	} else {
		cas, err = s.store.ListCAsByOwner(r.Context(), ActorOf(r.Context()).ID)
	}
	if err != nil {
		s.logger.Error("list CAs", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to list CAs")
		return
	}
	out := make([]caResponse, 0, len(cas))
	for _, c := range cas {
		out = append(out, s.toCAResponse(c))
	}
	writeJSON(w, http.StatusOK, out)
}

func (s *Server) handleGetCAByID(w http.ResponseWriter, r *http.Request) {
	id := chi.URLParam(r, "id")
	c, err := s.store.GetCA(r.Context(), id)
	if errors.Is(err, store.ErrNotFound) {
		writeError(w, http.StatusNotFound, "CA not found")
		return
	}
	if err != nil {
		writeError(w, http.StatusInternalServerError, "failed to get CA")
		return
	}
	if !s.canAccessCA(r, c) {
		writeError(w, http.StatusForbidden, "you do not own this CA")
		return
	}
	writeJSON(w, http.StatusOK, s.toCAResponse(c))
}

func (s *Server) handleCreateCA(w http.ResponseWriter, r *http.Request) {
	actor := ActorOf(r.Context())
	if s.master == nil {
		writeError(w, http.StatusServiceUnavailable, "CA creation requires NEBULA_MGMT_MASTER_KEY to be configured")
		return
	}

	var req createCARequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeError(w, http.StatusBadRequest, "invalid request body")
		return
	}
	if req.Name == "" {
		writeError(w, http.StatusBadRequest, "name is required")
		return
	}
	duration := 365 * 24 * time.Hour
	if req.Duration != "" {
		d, err := time.ParseDuration(req.Duration)
		if err != nil || d <= 0 {
			writeError(w, http.StatusBadRequest, "invalid duration")
			return
		}
		duration = d
	}

	mgr, err := pki.NewCA(req.Name, duration)
	if err != nil {
		s.logger.Error("generate CA", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to generate CA")
		return
	}
	rawKey := mgr.RawKey()
	defer keystore.Zeroize(rawKey)

	dek, wrappedDEK, err := s.master.GenerateDEK()
	if err != nil {
		writeError(w, http.StatusInternalServerError, "failed to generate DEK")
		return
	}
	defer keystore.Zeroize(dek)
	wrappedKey, err := keystore.SealWithDEK(dek, rawKey)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "failed to encrypt CA key")
		return
	}
	certPEM, err := mgr.CACertPEM()
	if err != nil {
		writeError(w, http.StatusInternalServerError, "marshal CA cert")
		return
	}
	fp, err := mgr.CACertFingerprint()
	if err != nil {
		writeError(w, http.StatusInternalServerError, "fingerprint CA cert")
		return
	}
	now := time.Now()
	c := &models.CA{
		ID:                   uuid.New().String(),
		Name:                 req.Name,
		OwnerOperatorID:      actor.ID,
		CertPEM:              string(certPEM),
		Fingerprint:          fp,
		NotBefore:            mgr.CACert().NotBefore(),
		NotAfter:             mgr.CACert().NotAfter(),
		Status:               models.CAStatusActive,
		EncryptedKeyDEK:      wrappedDEK.Ciphertext,
		NonceDEK:             wrappedDEK.Nonce,
		EncryptedKeyMaterial: wrappedKey.Ciphertext,
		NonceKey:             wrappedKey.Nonce,
		CreatedAt:            now,
		UpdatedAt:            now,
	}
	if err := s.store.CreateCA(r.Context(), c); err != nil {
		s.logger.Error("insert CA", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to store CA")
		return
	}
	s.recordAuditAction(r.Context(), auditCACreated, c.ID, c.Name)
	writeJSON(w, http.StatusCreated, s.toCAResponse(c))
}

func (s *Server) handleDeleteCA(w http.ResponseWriter, r *http.Request) {
	id := chi.URLParam(r, "id")
	c, err := s.store.GetCA(r.Context(), id)
	if errors.Is(err, store.ErrNotFound) {
		writeError(w, http.StatusNotFound, "CA not found")
		return
	}
	if err != nil {
		writeError(w, http.StatusInternalServerError, "failed to load CA")
		return
	}
	if !s.canAccessCA(r, c) {
		writeError(w, http.StatusForbidden, "you do not own this CA")
		return
	}
	if c.ID == s.defaultCAID {
		writeError(w, http.StatusForbidden, "the default CA cannot be deleted")
		return
	}
	if err := s.store.DeleteCA(r.Context(), id); err != nil {
		writeError(w, http.StatusConflict, err.Error())
		return
	}
	s.recordAuditAction(r.Context(), auditCADeleted, id, "")
	w.WriteHeader(http.StatusNoContent)
}

// canAccessCA checks ownership. Admins bypass.
func (s *Server) canAccessCA(r *http.Request, c *models.CA) bool {
	if actorIsAdmin(r.Context()) {
		return true
	}
	return ActorOf(r.Context()).ID == c.OwnerOperatorID
}

func (s *Server) handleRotateCA(w http.ResponseWriter, r *http.Request) {
	id := chi.URLParam(r, "id")
	oldCA, err := s.store.GetCA(r.Context(), id)
	if errors.Is(err, store.ErrNotFound) {
		writeError(w, http.StatusNotFound, "CA not found")
		return
	}
	if err != nil {
		s.logger.Error("get ca", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to get CA")
		return
	}
	if !s.canAccessCA(r, oldCA) {
		writeError(w, http.StatusForbidden, "you do not own this CA")
		return
	}

	newCA, err := pki.RotateAndStoreCA(r.Context(), s.store, s.master, s.logger, oldCA)
	if err != nil {
		if errors.Is(err, pki.ErrMasterRequired) {
			writeError(w, http.StatusBadRequest, "master key not configured")
			return
		}
		s.logger.Error("rotate ca", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to rotate CA")
		return
	}

	s.recordAuditAction(r.Context(), auditCARotated, newCA.ID, fmt.Sprintf("predecessor=%s", oldCA.ID))
	writeJSON(w, http.StatusOK, s.toCAResponse(newCA))
}

package api

import (
	"context"

	"github.com/juev/nebula-mesh/internal/models"
)

// actorContextKey scopes the authenticated operator on the request context.
type actorContextKeyType struct{}

var actorContextKey = actorContextKeyType{}

// ActorOf returns the operator attached to the request context. On protected
// API routes bearerAuth guarantees a non-nil value; nil indicates an
// unauthenticated context (e.g. public endpoints, tests).
func ActorOf(ctx context.Context) *models.Operator {
	op, _ := ctx.Value(actorContextKey).(*models.Operator)
	return op
}

// ActorName returns a stable string identifier for the actor, suitable for
// audit log entries. Returns "unknown" if no actor is on the context — this
// should not happen on routes guarded by bearerAuth.
func ActorName(ctx context.Context) string {
	if op := ActorOf(ctx); op != nil {
		return op.Username
	}
	return "unknown"
}

func withActor(ctx context.Context, op *models.Operator) context.Context {
	return context.WithValue(ctx, actorContextKey, op)
}

// actorIsAdmin reports whether the request's authenticated actor has the
// admin role. Returns false when no actor is on the context (fail-closed).
func actorIsAdmin(ctx context.Context) bool {
	op := ActorOf(ctx)
	return op != nil && op.Role == "admin"
}

// recordAuditAction writes an audit log entry and bumps the matching
// Prometheus audit counter. The DB write is best-effort to match prior
// fire-and-forget semantics; counter updates always run regardless of error.
func (s *Server) recordAuditAction(ctx context.Context, action, resource, details string) {
	_ = s.store.AddAuditEntry(ctx, ActorName(ctx), action, resource, details)
	s.metrics.recordAudit(action)
}

