func TestListCAs_ScopedToOwner(t *testing.T) {
	srv, _ := newServerWithMaster(t)

	// Two operators
	makeOp := func(role string) string {
		opID := uuid.New().String()
		if err := srv.store.CreateOperator(context.Background(), &models.Operator{
